// ../core/themes/dist/esm/opacify.mjs
function opacify(color2, opacity = 0.1) {
  if (typeof color2 != 'string') return color2
  if (color2.startsWith('hsl')) {
    const match = color2.match(/hsla?\((\d+),\s*(\d+)%,\s*(\d+)%(?:,\s*([\d.]+))?\)/)
    if (match) {
      const [, h, s, l] = match
      return `hsla(${h}, ${s}%, ${l}%, ${opacity})`
    }
  }
  if (color2.startsWith('#')) {
    let hex = color2.slice(1)
    if (
      (hex.length === 3 &&
        (hex = hex
          .split('')
          .map((c) => c + c)
          .join('')),
      hex.length === 6 || hex.length === 8)
    ) {
      const alphaHex = Math.round(opacity * 255)
        .toString(16)
        .padStart(2, '0')
      return `#${hex.slice(0, 6)}${alphaHex}`
    }
  }
  return color2
}
